// Cleanest, no side effects
function swap(a, b) {
  [a, b] = [b, a];
  return [a, b];
}

// Mutate array in place
function swapArray(arr, i, j) {
  [arr[i], arr[j]] = [arr[j], arr[i]];
  return arr;
}

function swapXOR(a, b) {
  a = a ^ b;
  b = a ^ b;
  a = a ^ b;
  return [a, b];
}

function swapMath(a, b) {
  a = a + b;
  b = a - b;
  a = a - b;
  return [a, b];
}
